export const CONGRESO_RESUMEN: DossierResumen[] = CONGRESO_FIXTURE.map(d => ({
  id: d.id,
  slug: d.slug,
  nombre_completo: d.nombre_completo,
  alias: d.alias,
  cargo_actual: d.cargo_actual,
  partido: d.partido,
  foto_url: d.foto_url,
  bio_corta: d.bio_corta,
  tags: d.tags,
  n_apartados: d.apartados.length,
  updated_at: d.updated_at,
}))

export function getCONGBySlug(slug: string): DossierCompleto | null {
  return CONGRESO_FIXTURE.find(d => d.slug === slug) ?? null
}
